/* ============================================================
 * connect_to_server: open a TCP connection to hostname:port.
 * Returns the fd on success or -1 on any failure (including DNS
 * failure).  Does NOT call exit() on error, unlike open_clientfd.
 * ============================================================ */

/*
 * Requires:
 *   hostname and port are NUL-terminated strings.
 *
 * Effects:
 *   Resolves hostname and attempts to connect on port.  Returns
 *   the connected socket fd on success, or -1 on any failure.
 */
static int
connect_to_server(const char *hostname, const char *port)
{
	struct addrinfo  hints, *listp, *p;
	int              clientfd = -1, rc;

	memset(&hints, 0, sizeof(struct addrinfo));
	hints.ai_socktype = SOCK_STREAM;
	hints.ai_flags    = AI_NUMERICSERV | AI_ADDRCONFIG;

	if ((rc = getaddrinfo(hostname, port, &hints, &listp)) != 0)
		return -1;  /* DNS failure: return -1, don't exit */

	for (p = listp; p != NULL; p = p->ai_next) {
		clientfd = socket(p->ai_family, p->ai_socktype, p->ai_protocol);
		if (clientfd < 0)
			continue;
		if (connect(clientfd, p->ai_addr, p->ai_addrlen) != -1)
			break;  /* Connected successfully */
		close(clientfd);
		clientfd = -1;
	}

	freeaddrinfo(listp);
	return clientfd;  /* -1 if all attempts failed */
}

